custom/center.exec:
sh -c '
WJSON="$HOME/.config/waybar/modules/window.json";
name="";
rwpath="";

# Prefer Hyprland when it is actually running
if [ -n "$HYPRLAND_INSTANCE_SIGNATURE" ] && command -v hyprctl >/dev/null 2>&1; then
  name=$(hyprctl -j activewindow 2>/dev/null | jq -r ".class // \"\"" );
  rwpath="hyprland/window";

# Otherwise try niri only if niri IPC responds
elif command -v niri >/dev/null 2>&1; then
  if niri msg --json focused-window >/dev/null 2>&1; then
    name=$(niri msg --json focused-window 2>/dev/null | jq -r "if .==null then \"\" else (.app_id // \"\") end");
    rwpath="niri/window";
  fi
fi;

[ -n "$name" ] || { echo "  Desktop"; exit 0; };

out=$(jq -r --arg name "$name" --arg rw "$rwpath" "
  (.[$rw].rewrite // {})
  | to_entries[]?
  | .key as \$k
  | select(\$name | test(\$k))
  | .value
" "$WJSON" 2>/dev/null | head -n1);

echo "${out:-$name}";
'
